  ('ZKKWng==', 'B', NULL, 'En un accidente de tráfico se puede sufrir un latigazo cervical si…', 'https://practicatest.com/views/layout/default/img/tests/B/03d1ec43c06c1baba81fd704b064858e.jpg', 'Lleva mal regulado el cinturón de seguridad', 'Se produce el efecto submarino', 'Lleva mal regulado el reposacabezas', 'c'),
