  ('ZZ2RoA==', 'B', NULL, '¿A qué velocidad máxima puede un automóvil con remolque y masa máxima autorizada de 700 kg conducir en una autovía?', 'https://practicatest.com/views/layout/default/img/tests/B/8d7977d3968cf27d8571e4b04c5db396.JPG', 'A 80 km/h', 'A 90 km/h', 'A 100 km/h', 'b'),
