  ('Y52Tng==', 'B', NULL, '¿Cuál de éstos tipos de vehículos está considerado como vehículo prioritario?', 'https://practicatest.com/views/layout/default/img/tests/B/69dc6155301f62e5f1930feafa28ec70.JPG', 'Vehículo privado con un niño menor de 12 años dentro', 'Vehículo de advertencia de obras', 'Camión de bomberos', 'c'),
