  ('ZJyYpg==', 'B', NULL, 'Descansar durante un viaje...', 'https://practicatest.com/views/layout/default/img/tests/B/0576bbd20d6e9876a225fe615b10cf4b.jpg', 'Es una forma de evitar la aparición de fatiga', 'Únicamente es necesario para conductores profesionales', 'Sólo es aconsejable para conductores noveles', 'a'),
