  ('ZZuUpQ==', 'B', NULL, 'El airbag es un elemento de seguridad. ¿Cuál es su función?', 'https://practicatest.com/views/layout/default/img/tests/B/63001bf36c796b19d70c8867932e17b4.jpg', 'Reforzar la eficacia del reposa cabezas.', 'Reforzar la eficacia del cinturón de seguridad.', 'Reforzar la eficacia del denominado ABS.', 'b'),
