  ('ZpqZ', 'B', NULL, '¿Se puede utilizar la luz indicadora de dirección de día en vía fuera de poblado?', 'https://practicatest.com/views/layout/default/img/tests/B/5a9a576390bb6283c792e0024183583d.jpg', 'Sí, pero únicamente en vías dentro de poblado', 'Sí', 'No', 'b'),
