  ('ZaKWpQ==', 'B', NULL, '¿Qué debes hacer en esta situación?', 'https://practicatest.com/views/layout/default/img/tests/B/8423d4f40b1160bda77cbf590ae63d81.jpeg', 'Detenerme, obedeciendo la señal del agente', 'Detenerme únicamente si también hay una señal vertical de Stop', 'Reducir la velocidad y seguir conduciendo', 'a'),
