  ('Y6GRnw==', 'B', NULL, '¿Cuál es el metodo más eficaz para cohibir una hemorragia?', 'https://practicatest.com/views/layout/default/img/tests/B/9540aa224c22c33c71f281a58e2ec81c.jpg', 'Presionar directamente sobre la herida', 'Mantener baja la zona de sangrado y taparla en todos los casos', 'Presionar en el trayecto de la arteria únicamente', 'a'),
