  ('Y5uWpg==', 'B', NULL, '¿Es lo mismo una detención que una parada en la vía?', 'https://practicatest.com/views/layout/default/img/tests/B/218548651fd2c69061acad660bf61fd3.jpg', 'Sí', 'No', 'Dependiendo de la situación se considerarán iguales o distintas', 'b'),
  ('ZJ6anQ==', 'B', NULL, '¿Quién tiene la responsabilidad por las infracciones cometidas sobre las normas de circulación?', 'https://practicatest.com/views/layout/default/img/tests/B/8c6f09202a67a3638640e317c6a39de1.jpg', 'El conductor y, si es menor de edad, sus padres o tutores legales, solidariamente', 'Siempre el conductor causante de la infracción cometida', 'El titular del vehículo', 'a'),
  ('aaGX', 'B', NULL, '¿Qué indica una línea continua dispuesta a lo ancho de un carril?', 'https://practicatest.com/views/layout/default/img/tests/B/99e11ada05a55729d4099797661008a2.jpg', 'Ceda el paso', 'Detención', 'Paso permitido', 'b'),
