  ('ap8=', 'B', NULL, '¿Cuál de éstos es un documento necesario para circular con un ciclomotor?', 'https://practicatest.com/views/layout/default/img/tests/B/5f14276885bb3de7c5d8a896ba6c53f3.JPG', 'El certificado de características técnicas', 'El justificante de estar al corriente del pago del impuesto municipal', 'El recibo de compra del ciclomotor', 'a'),
