  ('ZKGWnQ==', 'B', NULL, 'Esta señal sobre la calzada indica velocidad...', 'https://practicatest.com/views/layout/default/img/tests/B/5e21e6baa47d7ca46e00d4a7d0398089.jpg', 'Mínima en dicho carril', 'Máxima en dicho carril', 'Aconsejable en toda la calzada', 'b'),
  ('ZJ-Ung==', 'B', NULL, 'En una vía urbana de sentido único, está permitido estacionar en el lado...', 'https://practicatest.com/views/layout/default/img/tests/B/6540b49ea092b820e8795635b6b882f1.jpg', 'Derecho', 'Derecho o izquierdo, fuera de la calzada o el arcén', 'Derecho o izquierdo', 'c'),
