  ('ZJ2Ung==', 'B', NULL, 'Para ahorrar combustible es recomendable...', 'https://practicatest.com/views/layout/default/img/tests/B/3b44c9b76912eb562364c26ba104f046.png', 'Circular con el motor revolucionado', 'Evitar cambios de marcha innecesarios', 'Circular utilizando la marcha más corta posible', 'b'),
