  ('ZJyWpA==', 'B', NULL, 'Las técnicas de conducción preventiva se basan en los principios de...', 'https://practicatest.com/views/layout/default/img/tests/B/7cebb40ef72899994d4011fabd083e39.jpg', 'Visión, anticipación y gestión del espacio', 'Visión y gestión del espacio, únicamente', 'Visión, anticipación y gestión del tiempo', 'a'),
