  ('ZZ-ZoQ==', 'B', NULL, 'En este peaje, ¿qué se debe hacer?', 'https://practicatest.com/views/layout/default/img/tests/B/987f2f6f0bf66e39e825e808ea0166d5.jpg', 'Pasar sin detenerse porque no hay ninguna barrera', 'Detenerse en el punto de control porque lo indica la señal', 'Pasar sin detenerse ya que la flecha está en verde', 'b'),
