  ('ZZyWpA==', 'B', NULL, '¿Se puede atravesar la línea imaginaria de conos para cambiar de carril?', 'https://practicatest.com/views/layout/default/img/tests/B/08126f2995fdf9feb1ad4f95914cd841.jpg', 'Sí, para detenerse', 'No, porque está prohibido', 'Sí, para adelantar', 'b'),
