  ('ZZySoA==', 'B', NULL, '¿Cómo es el campo visual de los niños?', 'https://practicatest.com/views/layout/default/img/tests/B/81d284f1fbcdcd5cd5958b5bb9534b7d.jpg', 'El campo visual será el mismo que el de los adultos', 'Más reducido que el de los adultos', 'Más amplio que el de los adultos', 'b'),
