  ('Y56VpA==', 'B', NULL, '¿En qué marcha se debe circular en una curva si existe nieve en ellas?', 'https://practicatest.com/views/layout/default/img/tests/B/834c7f7ba7a7f6654e7d51d801db8360.jpg', 'En punto muerto', 'En primera marcha', 'En la relación de marchas más alta posible', 'c'),
