  ('Y5uapQ==', 'B', NULL, '¿Está prohibida la parada en los carriles destinados al uso de transporte público urbano?', 'https://practicatest.com/views/layout/default/img/tests/B/24765ef6f531924d31bfdab6d741d839.png', 'Está prohibido estacionar pero no parar', 'Sí, está totalmente prohibida', 'Está permitido siempre que la parada sea inferior a 2 minutos', 'b'),
